text:
Attached is a patch that fixes the problem pointed out in
bin/1095.

steve[~]$ cat > Makefile1
all:
.if defined(foo)
        @true
.elif !defined(foo) && !defined(foo)
        @echo ok
.else
        @echo not ok
.endif
steve[~]$ make -f Makefile1
ok
steve[~]$ cat > Makefile2
all:
.if defined(foo)
        @true
.else
.if !defined(foo) && \
        !defined(foo)
        @echo ok
.else
        @echo not ok
.endif
.endif
steve[~]$ make -f Makefile2
ok
steve[~]$ cat > Makefile3
all:
.if defined(foo)
        @true
.elif !defined(foo) && \
        !defined(foo)
        @echo ok
.else
        @echo not ok
.endif
steve[~]$ make -f Makefile3
ok
steve[~]$ 


Steve

